--
-- Name: calculate_order(numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_order(p_longitude numeric, p_latitude numeric, p_subtotal numeric) RETURNS TABLE(county text, state_rate numeric, county_rate numeric, city_rate numeric, special_rate numeric, composite_tax_rate numeric, tax_amount numeric, total_amount numeric, jurisdictions json)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        c.name::TEXT,
        r.state_rate,
        r.county_rate,
        r.city_rate,
        r.special_rate,
        (r.state_rate + r.county_rate + r.city_rate + r.special_rate),
        ROUND(p_subtotal * (r.state_rate + r.county_rate + r.city_rate + r.special_rate), 2),
        ROUND(p_subtotal * (1 + r.state_rate + r.county_rate + r.city_rate + r.special_rate), 2),
        json_build_object(
            'state', r.state_rate,
            'county', r.county_rate,
            'city', r.city_rate,
            'special', r.special_rate
        )
    FROM counties c
    JOIN ny_tax_rates r
        ON r.county_name = c.name
    WHERE ST_Contains(
        c.geom,
        ST_SetSRID(ST_Point(p_longitude, p_latitude), 4269)
    )
    LIMIT 1;
END;
$$;


ALTER FUNCTION public.calculate_order(p_longitude numeric, p_latitude numeric, p_subtotal numeric) OWNER TO postgres;

